export const getMarketData = async () => {
    const API_KEY = "apikey 1Hb7VKZ5BBt06yh3K6BeDF:3r0cUUdMGRFQ43n5uc11Ce";

    // Orijinal bağlantılar
    const goldUrl = "https://api.collectapi.com/economy/goldPrice";
    const currencyUrl = "https://api.collectapi.com/economy/allCurrency";

    try {
        const options = {
            method: 'GET',
            headers: {
                'authorization': API_KEY,
                'content-type': 'application/json'
            }
        };

        const [goldResponse, currencyResponse] = await Promise.all([
            fetch(goldUrl, options),
            fetch(currencyUrl, options)
        ]);

        const goldData = await goldResponse.json();
        const currencyData = await currencyResponse.json();

        // Eğer CollectAPI red verirse (örn: pakete abone değilseniz) sistemi çökertmeyelim hatayı gösterelim
        if (!goldData.success || !currencyData.success) {
            console.error("API Reddi:", goldData.message || currencyData.message);
            return [
                { symbol: "API UYARISI", price: (goldData.message || currencyData.message).substring(0, 15) + "...", trend: "down" }
            ];
        }

        // Güvenli filtreleme (Eğer isimlerde Türkçe karakter sorunu gelirse diye kapsayıcı arama yapıyoruz)
        const formattedGold = (goldData.result || [])
            .filter(item => item.name.includes("Gram") || item.name.includes("eyrek") || item.name.includes("Cumhuriyet") || item.name.includes("Ons"))
            .map(item => ({
                symbol: item.name.toUpperCase(),
                price: item.name.includes("Ons") ? `$${Number(item.selling).toFixed(2)}` : `₺${Number(item.selling).toFixed(2)}`,
                trend: item.rate > 0 ? 'up' : 'down'
            }));

        const formattedCurrency = (currencyData.result || [])
            .filter(item => ["USD", "EUR", "GBP"].includes(item.code))
            .map(item => ({
                symbol: `${item.code}/TRY`,
                price: `₺${Number(item.selling).toFixed(2)}`,
                trend: item.rate > 0 ? 'up' : 'down'
            }));

        return [...formattedCurrency, ...formattedGold];

    } catch (error) {
        // Eğer CORS (Güvenlik) engeline takıldıysa veya internet yoksa asıl sebebi yazdırıyoruz
        console.error("Yasal API limitlerine takılmış olabilirsiniz veya bağlantı hatası:", error);
        return [{ symbol: "CORS/AĞ HATASI", price: "Tarayıcı Engeli", trend: "down" }];
    }
};
